import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import './AuthPages.css';

const DEMO_CREDS = [
  { role: 'Admin', email: 'admin@rentforge.io', color: '#ef4444', icon: '⚙️' },
  { role: 'Manager', email: 'manager@rentforge.io', color: '#f4a11a', icon: '📋' },
  { role: 'Customer', email: 'ravi@ind.com', color: '#3b82f6', icon: '👤' },
  { role: 'Technician', email: 'kranthi@rentforge.io', color: '#22c55e', icon: '🔧' },
];

export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: 'admin@rentforge.io', password: 'password123' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const handleSubmit = async e => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(form.email, form.password);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.error || 'Login failed. Please try again.');
    } finally { setLoading(false); }
  };

  const fillDemo = (email) => setForm({ email, password: 'password123' });

  return (
    <div className="auth-screen">
      <div className="auth-grid" />
      <div className="auth-glow" />

      <div className="auth-box slide-up">
        <div className="auth-logo">RENTFORGE</div>
        <div className="auth-tagline">Equipment Rental Management System</div>
        <div className="auth-sub">SR University · DevOps &amp; Full Stack · 23CS102PE405</div>

        <div className="demo-pills">
          <p className="demo-label">Quick Login →</p>
          <div className="demo-row">
            {DEMO_CREDS.map(d => (
              <button key={d.role} className="demo-pill" onClick={() => fillDemo(d.email)}
                style={{ '--pill-color': d.color }}>
                {d.icon} {d.role}
              </button>
            ))}
          </div>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Email Address</label>
            <input name="email" type="email" className="form-control"
              value={form.email} onChange={handleChange} required placeholder="you@example.com" />
          </div>
          <div className="form-group">
            <label>Password</label>
            <input name="password" type="password" className="form-control"
              value={form.password} onChange={handleChange} required placeholder="••••••••" />
          </div>

          {error && <div className="auth-error">⚠ {error}</div>}

          <button type="submit" className="btn btn-primary" style={{ width: '100%', justifyContent: 'center', letterSpacing: '2px', marginTop: 4 }} disabled={loading}>
            {loading ? <span className="spinner" style={{ width: 18, height: 18, borderWidth: 2 }} /> : '→ LOGIN'}
          </button>
        </form>

        <p className="auth-link">
          Don't have an account? <Link to="/register">Register here</Link>
        </p>

        <div className="auth-hint">
          <span className="mono" style={{ fontSize: 11, color: 'var(--muted)' }}>
            All demo accounts use password: <strong style={{ color: 'var(--accent)' }}>password123</strong>
          </span>
        </div>
      </div>
    </div>
  );
}
